<?php
namespace App\Modules\Hr\Asset\Models;
use App\Modules\Hr\Asset\Enums\AssetStatus; use App\Modules\Hr\Core\Traits\BelongsToLegalEntity; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany; use Illuminate\Database\Eloquent\Relations\HasOne;
class HrAsset extends Model { use BelongsToLegalEntity; protected $fillable=['legal_entity_id','asset_category_id','asset_code','name','brand','model','serial_number','barcode','stock_item_reference','purchased_at','purchase_value','currency','status','notes','created_by','updated_by']; protected function casts():array{return ['purchased_at'=>'date','purchase_value'=>'decimal:2','status'=>AssetStatus::class];} public function category():BelongsTo{return $this->belongsTo(HrAssetCategory::class,'asset_category_id');} public function assignments():HasMany{return $this->hasMany(HrAssetAssignment::class,'asset_id');} public function activeAssignment():HasOne{return $this->hasOne(HrAssetAssignment::class,'asset_id')->where('status','assigned')->latestOfMany();} public function events():HasMany{return $this->hasMany(HrAssetEvent::class,'asset_id')->orderBy('created_at');} }
